ValidationRule.errorConditionFormula:
AND(
    /* Condición 1: El registro se está creando por primera vez */
    ISNEW(),

    /* Condición 2: El usuario seleccionó un estado cerrado */
    OR(
        ISPICKVAL(Status, "Closed - Converted"),
        ISPICKVAL(Status, "Closed - Not Converted")
    )
)
